+        let mut encoder = Encoder::new();
+        encoder.set_use_huffman(true);
+
+        // Encode many headers
+        let headers: Vec<Header> = (0..100)
+            .map(|i| Header::new(format!("x-header-{i}"), format!("value-{i}")))
